import React, { useEffect, useRef, useState, useCallback } from 'react';
import { COLORS, REST_ANGLE, START_ANGLE, END_ANGLE } from '../../constants';

interface TonearmProps {
  angle: number;
  isShivering: boolean;
  onDragStart: () => void;
  onDrag: (angle: number) => void;
  onDragEnd: () => void;
  parentRef: React.RefObject<HTMLDivElement>;
}

const Tonearm: React.FC<TonearmProps> = ({ 
  angle, 
  isShivering, 
  onDragStart, 
  onDrag, 
  onDragEnd,
  parentRef 
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const armRef = useRef<HTMLDivElement>(null);

  // Helper to calculate angle from mouse position relative to pivot
  const calculateAngle = useCallback((clientX: number, clientY: number) => {
    if (!parentRef.current) return 0;

    const parentRect = parentRef.current.getBoundingClientRect();

    // Pivot position in percentages: Left 82%, Top 18% (approx matching CSS)
    // We must use the exact computed pixels of the parent to determine the pivot point
    const pivotX = parentRect.left + (parentRect.width * 0.82);
    const pivotY = parentRect.top + (parentRect.height * 0.18);

    const dx = clientX - pivotX;
    const dy = clientY - pivotY;

    // Calculate angle in degrees
    let theta = Math.atan2(dy, dx) * (180 / Math.PI);

    // Normalize: atan2 returns -180 to 180.
    // 0 is 3 o'clock. 90 is 6 o'clock.
    // Our arm rests at roughly 25deg (pointing down-right)

    // Offset correction if needed based on the SVG orientation
    // Assuming the arm points 'down' by default, 90 degrees would be straight down.
    // Let's adjust so it feels natural.

    // Current mapping: 
    // visual angle 0 = pointing right.
    // visual angle 90 = pointing down.

    return theta;
  }, [parentRef]);

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    setIsDragging(true);
    onDragStart();

    // Capture pointer to handle drag outside the element
    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();

    const newAngle = calculateAngle(e.clientX, e.clientY);

    // Clamp angle to reasonable limits for the turntable
    // Rest is 25, End is ~55. Let's allow slightly wider for UX.
    const clampedAngle = Math.max(10, Math.min(newAngle, 70));

    onDrag(clampedAngle);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    setIsDragging(false);
    onDragEnd();
    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  return (
    <div 
      ref={armRef}
      className="absolute top-[18%] left-[82%] w-[20%] h-[60%] origin-top-left z-20"
      style={{ 
        transform: `rotate(${angle}deg)`,
        transition: isDragging ? 'none' : 'transform 0.5s cubic-bezier(0.25, 1, 0.5, 1)',
        touchAction: 'none',
        cursor: isDragging ? 'grabbing' : 'grab'
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
    >
      {/* Pivot Assembly (Static relative to arm rotation container, effectively the 'shoulder') */}
      {/* We need the pivot to look stationary while the arm moves? 
          Actually, the container rotates around the pivot point. 
          So the visual circle of the pivot should be outside this div or counter-rotated?
          Better approach: The visual pivot is on the Plinth. This div contains only the moving arm. 
      */}

      {/* The Arm Structure */}
      <div className={`relative w-full h-full pointer-events-none ${isShivering ? 'animate-shiver' : ''}`}>

        {/* Counterweight */}
        <div className="absolute -top-[15%] -left-[15%] w-[35%] h-[20%] bg-neutral-800 rounded-sm border border-neutral-600 shadow-md"></div>
        <div className="absolute -top-[12%] -left-[12%] w-[25%] h-[15%] rounded-full bg-neutral-400/20"></div>

        {/* Main Shaft (Gold/Brass) */}
        <div 
          className="absolute top-0 left-0 w-[6%] h-[80%] rounded-full shadow-lg"
          style={{ 
            background: `linear-gradient(90deg, ${COLORS.goldDark}, ${COLORS.gold} 40%, ${COLORS.goldDark})`,
            marginLeft: '-3%' // Center on pivot
          }}
        ></div>

        {/* S-Bend (Simulated via another segment or SVG) */}
        {/* Simplified: Angled Headhsell connector */}
         <div 
          className="absolute top-[80%] left-[-3%] w-[6%] h-[10%] rounded-full origin-top"
          style={{ 
            background: `linear-gradient(90deg, ${COLORS.goldDark}, ${COLORS.gold} 40%, ${COLORS.goldDark})`,
            transform: 'rotate(-20deg)'
          }}
        ></div>

        {/* Headshell (Black) */}
        <div 
          className="absolute top-[88%] left-[-15%] w-[25%] h-[12%] bg-neutral-900 rounded-sm shadow-md flex items-center justify-center pointer-events-auto"
          style={{ transform: 'rotate(-20deg)' }}
        >
          {/* Finger Lift */}
          <div className="absolute right-[-10%] top-[20%] w-[40%] h-[4px] bg-neutral-800 rounded-full rotate-12"></div>
        </div>

      </div>
    </div>
  );
};

export default Tonearm;

