import React, { useState, useEffect, useRef } from 'react';
import { PlayState, Track } from '../../types';
import { COLORS, START_ANGLE, END_ANGLE, REST_ANGLE } from '../../constants';
import Platter from './Platter';
import Tonearm from './Tonearm';
import { StartButton, PitchSlider } from './Controls';

interface TurntableProps {
  currentTrack: Track | null;
  onTrackEnd: () => void;
}

const Turntable: React.FC<TurntableProps> = ({ currentTrack, onTrackEnd }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [armAngle, setArmAngle] = useState(REST_ANGLE);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const animationRef = useRef<number>();
  const containerRef = useRef<HTMLDivElement>(null);

  // Audio Initialization
  useEffect(() => {
    if (currentTrack) {
        setAudioUrl(currentTrack.audioUrl);
        // Reset arm if track changes? Maybe not, keep the vibe authentic.
        // But for UX, let's reset to start if we load a new track while stopped.
        if (!isPlaying) {
             setArmAngle(REST_ANGLE);
        }
    }
  }, [currentTrack]);

  // Audio Playback Logic
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPlaying) {
        // Only play audio if arm is over the record
        if (armAngle >= START_ANGLE && armAngle <= END_ANGLE) {
            audioRef.current.play().catch(e => console.log("Audio play failed (interaction needed)", e));
            // Calculate current time based on arm position
            const progress = (armAngle - START_ANGLE) / (END_ANGLE - START_ANGLE);
            const duration = audioRef.current.duration || 0;
            if (duration && Math.abs(audioRef.current.currentTime - (progress * duration)) > 1) {
                // Only seek if significantly different to avoid stutter
                audioRef.current.currentTime = progress * duration;
            }
        } else {
            audioRef.current.pause();
        }
    } else {
        audioRef.current.pause();
    }
  }, [isPlaying, armAngle]);

  // Animation Loop (Physics)
  useEffect(() => {
    let lastTime = performance.now();
    let currentVelocity = 0; // degrees per frame
    const maxVelocity = 3; // 33 RPM approx speed normalized to frames

    const animate = (time: number) => {
      const delta = time - lastTime;
      lastTime = time;

      // 1. Platter Rotation Logic (Inertia)
      if (isPlaying) {
        // Accelerate
        currentVelocity = Math.min(currentVelocity + 0.05, maxVelocity);
      } else {
        // Decelerate (friction)
        currentVelocity = Math.max(currentVelocity - 0.05, 0);
      }

      if (currentVelocity > 0) {
          setRotation(prev => (prev + currentVelocity) % 360);
      }

      // 2. Tonearm Tracking Logic (only if playing and arm is on record)
      // If platter is spinning at sufficient speed and arm is on record
      if (currentVelocity > 2 && armAngle >= START_ANGLE && armAngle < END_ANGLE) {
         // Move arm slowly towards center based on track duration
         // This is a visual approximation. Real syncing happens in the audio effect above or vice versa.
         // Let's drive the arm with the audio time if audio is playing
         if (audioRef.current && !audioRef.current.paused) {
             const duration = audioRef.current.duration || 180;
             const progress = audioRef.current.currentTime / duration;
             const newAngle = START_ANGLE + (progress * (END_ANGLE - START_ANGLE));
             setArmAngle(newAngle);

             if (progress >= 1) {
                 onTrackEnd();
             }
         }
      }

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
        if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying, armAngle, onTrackEnd]);


  const handleDragStart = () => {
      // Pause updates from audio while dragging
      if (audioRef.current) audioRef.current.pause();
  };

  const handleDrag = (angle: number) => {
      setArmAngle(angle);
  };

  const handleDragEnd = () => {
      // If we dropped the needle on the record and the motor is running, resume/seek
      if (isPlaying && armAngle >= START_ANGLE && armAngle <= END_ANGLE) {
           if (audioRef.current) {
                const duration = audioRef.current.duration || 1;
                const progress = (armAngle - START_ANGLE) / (END_ANGLE - START_ANGLE);
                audioRef.current.currentTime = progress * duration;
                audioRef.current.play();
           }
      }
  };

  return (
    <div ref={containerRef} className="relative w-full max-w-2xl aspect-square select-none p-4">
       {/* Audio Element */}
       <audio ref={audioRef} src={audioUrl || ''} loop={false} />

       {/* The Monolith Container */}
       <div className="relative w-full h-full shadow-[0_20px_50px_rgba(0,0,0,0.5)] rounded-lg overflow-hidden transform transition-transform hover:scale-[1.01] duration-500">

           {/* 1. Plinth (Chassis) */}
           <div 
             className="absolute inset-0 texture-brushed"
             style={{
                background: `linear-gradient(135deg, ${COLORS.plinthLight} 0%, ${COLORS.plinthDark} 100%)`
             }}
           >
                {/* Metallic Noise/Grain Overlay */}
                <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/brushed-alum.png')] mix-blend-overlay"></div>

                {/* Branding/Text */}
                <div className="absolute bottom-6 right-6 flex flex-col items-end opacity-80">
                    <span className="font-serif italic text-gold-500 text-yellow-600 text-lg">Technics</span>
                    <span className="text-[8px] font-mono text-neutral-400 tracking-widest uppercase">Quartz Direct Drive Turntable System SL-1200MK2</span>
                </div>
           </div>

           {/* 2. Platter Assembly */}
           <Platter 
             isPlaying={isPlaying} 
             track={currentTrack} 
             rotation={rotation}
           />

           {/* 3. Tonearm Assembly */}
           {/* Pivot Base Visual */}
           <div className="absolute top-[12%] right-[12%] w-[16%] h-[16%] rounded-full bg-black/40 border border-black/60 shadow-inner"></div>
           <div className="absolute top-[14%] right-[14%] w-[12%] h-[12%] rounded-full bg-neutral-800 shadow-[0_4px_10px_rgba(0,0,0,0.5)] border border-neutral-700"></div>

           <Tonearm 
             angle={armAngle}
             isShivering={isPlaying && armAngle > START_ANGLE && armAngle < END_ANGLE}
             onDragStart={handleDragStart}
             onDrag={handleDrag}
             onDragEnd={handleDragEnd}
             parentRef={containerRef}
           />

           {/* 4. Controls */}
           <StartButton isPlaying={isPlaying} onTogglePlay={() => setIsPlaying(!isPlaying)} />
           <PitchSlider />

           {/* Power Dial / Extra detail */}
           <div className="absolute bottom-[20%] left-[6%] w-8 h-8 rounded-full bg-neutral-800 border border-neutral-600 shadow-lg flex items-center justify-center">
               <div className="w-1 h-4 bg-neutral-900 rounded-full transform rotate-45"></div>
           </div>
           <div className="absolute bottom-[24%] left-[6.5%] text-[6px] text-neutral-400 font-mono">OFF • ON</div>

       </div>
    </div>
  );
};

export default Turntable;

