// Physics Constants
// Adjusted for a 4:3 (approx 1.33) aspect ratio plinth
// Pivot is in the top-right quadrant
export const ARM_PIVOT_X_PCT = 78; 
export const ARM_PIVOT_Y_PCT = 20;

// Angles in degrees (0 = 3 o'clock, 90 = 6 o'clock)
// Pivot is Top-Right. Arm points Down-Left towards center.
// Rest position (off platter): ~75 degrees (Pointing mostly down)
// Start of Record (Lead-in): ~108 degrees
// End of Record (Run-out): ~138 degrees
export const REST_ANGLE = 75;
export const START_ANGLE = 108;
export const END_ANGLE = 142;

import React, { useState, useEffect, useRef } from 'react';
import { PlayState, Track } from '../../types';
import { COLORS, START_ANGLE, END_ANGLE, REST_ANGLE } from '../../constants';
import Platter from './Platter';
import Tonearm from './Tonearm';
import { StartButton, PitchSlider } from './Controls';

interface TurntableProps {
  currentTrack: Track | null;
  onTrackEnd: () => void;
}

const Turntable: React.FC<TurntableProps> = ({ currentTrack, onTrackEnd }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [armAngle, setArmAngle] = useState(REST_ANGLE);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const animationRef = useRef<number>();
  const containerRef = useRef<HTMLDivElement>(null);

  // Audio Initialization
  useEffect(() => {
    if (currentTrack) {
        setAudioUrl(currentTrack.audioUrl);
        if (!isPlaying) {
             setArmAngle(REST_ANGLE);
        }
    }
  }, [currentTrack]);

  // Audio Playback Logic
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPlaying) {
        // Play only if arm is in the "groove zone"
        if (armAngle >= START_ANGLE && armAngle <= END_ANGLE) {
            audioRef.current.play().catch(e => console.log("Audio play failed (interaction needed)", e));

            const progress = (armAngle - START_ANGLE) / (END_ANGLE - START_ANGLE);
            const duration = audioRef.current.duration || 0;
            if (duration && Math.abs(audioRef.current.currentTime - (progress * duration)) > 1) {
                audioRef.current.currentTime = progress * duration;
            }
        } else {
            audioRef.current.pause();
        }
    } else {
        audioRef.current.pause();
    }
  }, [isPlaying, armAngle]);

  // Animation Loop (Physics)
  useEffect(() => {
    let lastTime = performance.now();
    let currentVelocity = 0; 
    const maxVelocity = 3;

    const animate = (time: number) => {
      const delta = time - lastTime;
      lastTime = time;

      // 1. Platter Rotation
      if (isPlaying) {
        currentVelocity = Math.min(currentVelocity + 0.05, maxVelocity);
      } else {
        currentVelocity = Math.max(currentVelocity - 0.05, 0);
      }

      if (currentVelocity > 0) {
          setRotation(prev => (prev + currentVelocity) % 360);
      }

      // 2. Tonearm Auto-tracking (Visual only)
      // Only track if playing and needle is on record
      if (currentVelocity > 2 && armAngle >= START_ANGLE && armAngle < END_ANGLE) {
         if (audioRef.current && !audioRef.current.paused) {
             const duration = audioRef.current.duration || 180;
             const progress = audioRef.current.currentTime / duration;
             const newAngle = START_ANGLE + (progress * (END_ANGLE - START_ANGLE));
             setArmAngle(newAngle);

             if (progress >= 1) {
                 onTrackEnd();
             }
         }
      }

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
        if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying, armAngle, onTrackEnd]);


  const handleDragStart = () => {
      if (audioRef.current) audioRef.current.pause();
  };

  const handleDrag = (angle: number) => {
      setArmAngle(angle);
  };

  const handleDragEnd = () => {
      if (isPlaying && armAngle >= START_ANGLE && armAngle <= END_ANGLE) {
           if (audioRef.current) {
                const duration = audioRef.current.duration || 1;
                const progress = (armAngle - START_ANGLE) / (END_ANGLE - START_ANGLE);
                audioRef.current.currentTime = progress * duration;
                audioRef.current.play();
           }
      }
  };

  return (
    <div ref={containerRef} className="relative w-full max-w-3xl aspect-[1.3/1] select-none p-4">
       <audio ref={audioRef} src={audioUrl || ''} loop={false} />

       {/* The Monolith Container - Wider Aspect Ratio */}
       <div className="relative w-full h-full shadow-[0_25px_60px_rgba(0,0,0,0.6)] rounded-lg overflow-hidden transform transition-transform hover:scale-[1.005] duration-500 bg-neutral-900">

           {/* 1. Plinth (Chassis) */}
           <div 
             className="absolute inset-0 texture-brushed"
             style={{
                background: `linear-gradient(160deg, ${COLORS.plinthLight} 0%, ${COLORS.plinthDark} 100%)`
             }}
           >
                <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/brushed-alum.png')] mix-blend-overlay"></div>

                {/* Branding */}
                <div className="absolute bottom-5 right-8 flex flex-col items-end opacity-90">
                    <span className="font-serif italic text-gold-500 text-[#d4af37] text-xl drop-shadow-sm">Technics</span>
                    <span className="text-[7px] font-mono text-neutral-400 tracking-[0.2em] uppercase mt-1">Quartz Direct Drive Turntable System SL-1200MK2</span>
                </div>
           </div>

           {/* 2. Platter Assembly - Positioned left-center */}
           <div className="absolute top-[50%] left-[36%] w-[82%] h-auto aspect-square -translate-x-1/2 -translate-y-1/2">
                <Platter isPlaying={isPlaying} track={currentTrack} rotation={rotation} />
           </div>

           {/* 3. Tonearm Assembly */}
           {/* Detailed Pivot Base Visuals on Plinth */}
           <div className="absolute top-[20%] right-[22%] z-10 pointer-events-none">
              {/* Outer Base Ring */}
              <div className="absolute top-0 left-0 -translate-x-1/2 -translate-y-1/2 w-32 h-32 rounded-full bg-neutral-900 border-[3px] border-[#2a2a2a] shadow-[0_5px_15px_rgba(0,0,0,0.5)]"></div>

              {/* VTA Adjustment Ring (Silver numbers) */}
              <div className="absolute top-0 left-0 -translate-x-1/2 -translate-y-1/2 w-28 h-28 rounded-full bg-[#1a1a1a] border border-neutral-700 flex items-center justify-center">
                  <div className="w-full h-full rounded-full border-[2px] border-dashed border-neutral-600 opacity-50 animate-spin-slow" style={{ animationDuration: '60s' }}></div>
              </div>

              {/* Inner Pivot Housing */}
              <div className="absolute top-0 left-0 -translate-x-1/2 -translate-y-1/2 w-20 h-20 rounded-full bg-gradient-to-br from-[#333] to-[#111] shadow-[inset_0_2px_4px_rgba(255,255,255,0.1)] border border-neutral-800"></div>

              {/* Anti-skate Dial (Small satellite dial) */}
              <div className="absolute top-[30px] right-[-50px] w-10 h-10 rounded-full bg-neutral-800 border border-neutral-600 shadow-md flex items-center justify-center">
                   <div className="w-8 h-8 rounded-full border border-neutral-600 bg-gradient-to-tr from-neutral-800 to-neutral-700">
                      <div className="w-[1px] h-3 bg-white mx-auto mt-1"></div>
                   </div>
              </div>
           </div>

           {/* Arm Rest Post */}
           <div className="absolute top-[35%] right-[14%] w-4 h-8 bg-neutral-800 rounded-sm shadow-md border border-neutral-700 z-10 flex flex-col items-center justify-between py-1">
                <div className="w-3 h-3 rounded-full bg-black/50"></div>
                <div className="w-5 h-[2px] bg-neutral-600"></div>
           </div>

           {/* Interactive Tonearm Layer */}
           <Tonearm 
             angle={armAngle}
             isShivering={isPlaying && armAngle > START_ANGLE && armAngle < END_ANGLE}
             onDragStart={handleDragStart}
             onDrag={handleDrag}
             onDragEnd={handleDragEnd}
             parentRef={containerRef}
           />

           {/* 4. Controls */}
           <StartButton isPlaying={isPlaying} onTogglePlay={() => setIsPlaying(!isPlaying)} />
           <PitchSlider />

           {/* Power Dial */}
           <div className="absolute bottom-[18%] left-[7%] z-10">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-neutral-700 to-neutral-900 border border-neutral-600 shadow-[0_4px_8px_rgba(0,0,0,0.6)] flex items-center justify-center">
                  <div className="w-1.5 h-5 bg-black rounded-full shadow-[inset_0_0_2px_rgba(255,255,255,0.2)] transform rotate-45"></div>
              </div>
              <div className="absolute top-full left-1/2 -translate-x-1/2 mt-2 text-[6px] text-neutral-400 font-mono tracking-widest whitespace-nowrap">OFF • ON</div>
           </div>

       </div>
    </div>
  );
};

export default Turntable;

