import React, { useRef, useState, useCallback } from 'react';
import { COLORS, REST_ANGLE, START_ANGLE, END_ANGLE } from '../../constants';

interface TonearmProps {
  angle: number;
  isShivering: boolean;
  onDragStart: () => void;
  onDrag: (angle: number) => void;
  onDragEnd: () => void;
  parentRef: React.RefObject<HTMLDivElement>;
}

const Tonearm: React.FC<TonearmProps> = ({ 
  angle, 
  isShivering, 
  onDragStart, 
  onDrag, 
  onDragEnd, 
  parentRef 
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const armRef = useRef<HTMLDivElement>(null);

  // Pivot point percentages relative to the container (Must match constants/CSS)
  // X: 78%, Y: 20%
  const PIVOT_X_PCT = 78;
  const PIVOT_Y_PCT = 20;

  const calculateAngle = useCallback((clientX: number, clientY: number) => {
    if (!parentRef.current) return 0;

    const parentRect = parentRef.current.getBoundingClientRect();
    const pivotX = parentRect.left + (parentRect.width * (PIVOT_X_PCT / 100));
    const pivotY = parentRect.top + (parentRect.height * (PIVOT_Y_PCT / 100));

    const dx = clientX - pivotX;
    const dy = clientY - pivotY;

    let theta = Math.atan2(dy, dx) * (180 / Math.PI);

    // Normalize logic: 
    // Atan2: 0 is Right, 90 is Down, 180 is Left.
    // We want to constrain to our operational sector (roughly 70 to 150 degrees).
    return theta;
  }, [parentRef]);

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    setIsDragging(true);
    onDragStart();
    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    const newAngle = calculateAngle(e.clientX, e.clientY);
    // Hard constraints to prevent 360 spinning
    const clampedAngle = Math.max(REST_ANGLE - 5, Math.min(newAngle, END_ANGLE + 15));
    onDrag(clampedAngle);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    setIsDragging(false);
    onDragEnd();
    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  return (
    <div 
      ref={armRef}
      className="absolute z-20 w-[40%] h-[50%] origin-top-left"
      style={{ 
        top: `${PIVOT_Y_PCT}%`,
        left: `${PIVOT_X_PCT}%`,
        transform: `rotate(${angle}deg)`,
        transition: isDragging ? 'none' : 'transform 0.6s cubic-bezier(0.2, 1.2, 0.5, 1)', // Little bounce for realism
        touchAction: 'none',
        cursor: isDragging ? 'grabbing' : 'grab'
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
    >
      <div className={`relative w-full h-full pointer-events-none ${isShivering ? 'animate-shiver' : ''}`}>

        {/* --- GIMBAL ASSEMBLY (The rotating part) --- */}
        {/* Center Pivot Cap */}
        <div className="absolute -top-[20px] -left-[20px] w-[40px] h-[40px] rounded-full bg-neutral-900 border border-neutral-600 shadow-lg z-30">
             {/* Screw Detail */}
             <div className="absolute inset-[30%] rounded-full bg-neutral-800 border border-neutral-700 flex items-center justify-center">
                 <div className="w-[60%] h-[2px] bg-neutral-900"></div>
                 <div className="h-[60%] w-[2px] bg-neutral-900 absolute"></div>
             </div>
        </div>

        {/* Gimbal Yoke (Black/Silver Frame) */}
        <div className="absolute -top-[30px] -left-[30px] w-[60px] h-[60px] rounded-full border-[6px] border-neutral-800 z-20 border-t-transparent opacity-90 rotate-45"></div>


        {/* --- COUNTERWEIGHT --- */}
        <div className="absolute top-[-4px] left-[-80px] w-[70px] h-[28px] z-10">
           {/* The weight cylinder */}
           <div className="w-full h-full bg-gradient-to-b from-neutral-600 via-neutral-400 to-neutral-700 rounded-sm border border-neutral-700 shadow-md flex items-center">
               <div className="w-full h-[80%] border-l border-r border-neutral-500/50 mx-2"></div>
           </div>
           {/* The stub connecting to pivot */}
           <div className="absolute right-[-10px] top-[8px] w-[10px] h-[12px] bg-neutral-500"></div>
        </div>


        {/* --- S-SHAPED TONEARM TUBE --- */}
        {/* Using SVG for precise S-curve */}
        <svg 
            width="300" 
            height="100" 
            viewBox="0 0 300 100" 
            className="absolute top-[-6px] left-[10px] overflow-visible drop-shadow-md z-20"
            style={{ pointerEvents: 'none' }}
        >
            <defs>
                <linearGradient id="goldGradient" x1="0%" y1="0%" x2="0%" y2="100%">
                    <stop offset="0%" stopColor={COLORS.goldDark} />
                    <stop offset="40%" stopColor={COLORS.gold} />
                    <stop offset="60%" stopColor={COLORS.gold} />
                    <stop offset="100%" stopColor={COLORS.goldDark} />
                </linearGradient>
            </defs>
            {/* 
                Path logic:
                Start at (0, 6) - near pivot (center of tube height)
                Straight line out
                Curve Left
                Curve Right (S-bend)
                End at Headshell
            */}
            <path 
                d="M 0,6 L 120,6 C 160,6 170,20 200,20 L 220,20 C 240,20 250,10 260,10" 
                fill="none" 
                stroke="url(#goldGradient)" 
                strokeWidth="10" 
                strokeLinecap="butt"
            />
        </svg>

        {/* --- HEADSHELL --- */}
        {/* Position needs to match the end of the SVG path approx (260, 10) */}
        <div 
            className="absolute z-30 pointer-events-auto hover:scale-105 transition-transform"
            style={{ 
                left: '258px', // End of SVG path X
                top: '-4px',   // Adjusted for alignment
                transform: 'rotate(-15deg)', // Angle of the headshell
                transformOrigin: 'left center'
            }}
        >
            {/* Headshell Body */}
            <div className="w-[60px] h-[22px] bg-neutral-900 rounded-sm border border-neutral-700 shadow-lg relative">
                {/* Finger Lift */}
                <div className="absolute right-[-2px] top-[4px] w-[35px] h-[4px] bg-neutral-800 rounded-full origin-left rotate-[-20deg] shadow-sm"></div>

                {/* Cartridge screws */}
                <div className="absolute top-[6px] left-[15px] w-1.5 h-1.5 rounded-full bg-neutral-500"></div>
                <div className="absolute top-[6px] left-[30px] w-1.5 h-1.5 rounded-full bg-neutral-500"></div>

                {/* Stylus visual (underneath) */}
                <div className="absolute -bottom-[2px] left-[20px] w-3 h-3 bg-red-600 rounded-full opacity-0"></div> 
            </div>
        </div>

      </div>
    </div>
  );
};

export default Tonearm;

