import React, { useRef, useState, useCallback, useEffect } from 'react';
import { COLORS, REST_ANGLE, START_ANGLE, END_ANGLE } from '../../constants';

interface TonearmProps {
  angle: number;
  isShivering: boolean;
  onDragStart: () => void;
  onDrag: (angle: number) => void;
  onDragEnd: () => void;
  onCueToggle: (isUp: boolean) => void; // New prop for Cue Lever
  isCueUp: boolean;
  parentRef: React.RefObject<HTMLDivElement>;
}

const Tonearm: React.FC<TonearmProps> = ({ 
  angle, 
  isShivering, 
  onDragStart, 
  onDrag, 
  onDragEnd, 
  onCueToggle,
  isCueUp,
  parentRef 
}) => {
  const [isDragging, setIsDragging] = useState(false);

  // Pivot point percentages relative to the 3:2 container
  const PIVOT_X_PCT = 80;
  const PIVOT_Y_PCT = 30;

  const calculateAngle = useCallback((clientX: number, clientY: number) => {
    if (!parentRef.current) return 0;

    const parentRect = parentRef.current.getBoundingClientRect();
    const pivotX = parentRect.left + (parentRect.width * (PIVOT_X_PCT / 100));
    const pivotY = parentRect.top + (parentRect.height * (PIVOT_Y_PCT / 100));

    const dx = clientX - pivotX;
    const dy = clientY - pivotY;

    let theta = Math.atan2(dy, dx) * (180 / Math.PI);
    return theta;
  }, [parentRef]);

  const handlePointerDown = (e: React.PointerEvent) => {
    if (isCueUp) return; // Cannot drag if arm is locked in Up position? Actually usually you can, but let's allow it.
    e.preventDefault();
    setIsDragging(true);
    onDragStart();
    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    const newAngle = calculateAngle(e.clientX, e.clientY);
    const clampedAngle = Math.max(REST_ANGLE - 5, Math.min(newAngle, END_ANGLE + 15));
    onDrag(clampedAngle);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    setIsDragging(false);
    onDragEnd();
    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  return (
    <>
      {/* BASE & CUE MECHANISM (Fixed on Plinth) */}
      <div 
        className="absolute z-20 pointer-events-none"
        style={{ top: `${PIVOT_Y_PCT}%`, left: `${PIVOT_X_PCT}%` }}
      >
           {/* Gimbal Base Ring */}
           <div className="absolute top-0 left-0 -translate-x-1/2 -translate-y-1/2 w-40 h-40 rounded-full bg-[#151515] border-[2px] border-[#222] shadow-[0_10px_20px_rgba(0,0,0,0.6)]"></div>

           {/* Anti-Skate Dial */}
           <div className="absolute top-[40px] right-[-50px] w-12 h-12 rounded-full bg-[#1a1a1a] border border-neutral-700 shadow-lg flex items-center justify-center">
               <div className="w-10 h-10 rounded-full border border-neutral-600 bg-gradient-to-tr from-neutral-800 to-neutral-700 flex items-center justify-center text-[6px] text-neutral-400 font-mono">
                  2.5
               </div>
           </div>

           {/* CUE LEVER (Interactable) */}
           <div 
              className="absolute top-[30px] right-[-20px] z-30 pointer-events-auto cursor-pointer group"
              onClick={() => onCueToggle(!isCueUp)}
           >
                {/* Lever Base */}
                <div className="w-10 h-10 rounded-full bg-[#111] border border-neutral-700 flex items-center justify-center shadow-md">
                     {/* The Lever Arm */}
                     <div 
                        className="w-1 h-14 bg-gradient-to-b from-[#8F7124] to-[#D4AF37] rounded-full origin-bottom transition-transform duration-500 ease-in-out shadow-sm"
                        style={{ transform: isCueUp ? 'rotate(-10deg) translateY(-5px)' : 'rotate(45deg)' }}
                     >
                        {/* Lever Tip */}
                        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-2 h-4 bg-black rounded-full"></div>
                     </div>
                </div>
                {/* Label */}
                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-1 text-[6px] text-neutral-500 font-mono opacity-0 group-hover:opacity-100 transition-opacity">CUE</div>
           </div>
      </div>

      {/* ROTATING TONEARM ASSEMBLY */}
      <div 
        className="absolute z-30 w-[32%] h-[50%] origin-top-left"
        style={{ 
          top: `${PIVOT_Y_PCT}%`,
          left: `${PIVOT_X_PCT}%`,
          transform: `rotate(${angle}deg)`,
          transition: isDragging ? 'none' : 'transform 0.4s cubic-bezier(0.2, 1.0, 0.5, 1)', 
          touchAction: 'none',
          cursor: isDragging ? 'grabbing' : 'grab',
          // Lift effect: simple scale up slightly or add shadow logic
          filter: isCueUp ? 'drop-shadow(10px 10px 10px rgba(0,0,0,0.5))' : 'none'
        }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        <div className={`relative w-full h-full pointer-events-none ${isShivering && !isCueUp ? 'animate-shiver' : ''}`}>

          {/* Main Bearing Housing (Yoke) */}
          <div className="absolute -top-[25px] -left-[25px] w-[50px] h-[50px] rounded-full border-[6px] border-[#1a1a1a] z-30 border-t-transparent rotate-45"></div>
          <div className="absolute -top-[15px] -left-[15px] w-[30px] h-[30px] rounded-full bg-gradient-to-br from-[#333] to-black border border-neutral-700 z-30 shadow-lg"></div>

          {/* Counterweight */}
          <div className="absolute top-[-5px] left-[-85px] w-[80px] h-[32px] z-10">
             <div className="w-full h-full bg-gradient-to-b from-[#2a2a2a] via-[#444] to-[#2a2a2a] rounded-[2px] border border-neutral-700 shadow-md flex items-center relative">
                 <div className="absolute inset-y-0 left-[20%] w-[1px] bg-black/50"></div>
                 <div className="absolute inset-y-0 left-[25%] w-[1px] bg-black/50"></div>
                 {/* Brass End Cap */}
                 <div className="absolute right-0 top-0 bottom-0 w-2 bg-[#8F7124] rounded-r-[2px]"></div>
             </div>
          </div>

          {/* Brass S-Curve Arm (Shortened ~20%) */}
          <svg 
              width="300" 
              height="100" 
              viewBox="0 0 300 100" 
              className="absolute top-[-8px] left-[10px] overflow-visible drop-shadow-lg z-20"
              style={{ pointerEvents: 'none' }}
          >
              <defs>
                  <linearGradient id="brassGradient" x1="0%" y1="0%" x2="0%" y2="100%">
                      <stop offset="0%" stopColor="#8F7124" />
                      <stop offset="40%" stopColor="#D4AF37" />
                      <stop offset="60%" stopColor="#D4AF37" />
                      <stop offset="100%" stopColor="#8F7124" />
                  </linearGradient>
              </defs>
              <path 
                  d="M 0,8 L 112,8 C 152,8 160,25 192,25 L 208,25 C 224,25 232,12 240,12" 
                  fill="none" 
                  stroke="url(#brassGradient)" 
                  strokeWidth="10" 
                  strokeLinecap="butt"
              />
          </svg>

          {/* Headshell (Repositioned for shorter arm) */}
          <div 
              className="absolute z-30 pointer-events-auto hover:scale-105 transition-transform"
              style={{ 
                  left: '238px', 
                  top: '-3px',
                  transform: 'rotate(-18deg)', 
                  transformOrigin: 'left center'
              }}
          >
              <div className="w-[65px] h-[24px] bg-[#111] rounded-[1px] border border-neutral-700 shadow-xl relative">
                  {/* Finger Lift */}
                  <div className="absolute right-[-4px] top-[4px] w-[40px] h-[4px] bg-[#222] rounded-full origin-left rotate-[-20deg] shadow-sm border border-neutral-800"></div>

                  {/* Gold Screws */}
                  <div className="absolute top-[8px] left-[18px] w-1.5 h-1.5 rounded-full bg-[#D4AF37] shadow-sm"></div>
                  <div className="absolute top-[8px] left-[35px] w-1.5 h-1.5 rounded-full bg-[#D4AF37] shadow-sm"></div>
              </div>
          </div>

        </div>
      </div>
    </>
  );
};

