import React, { useState, useEffect, useRef } from 'react';
import { PlayState, Track } from '../../types';
import { COLORS, START_ANGLE, END_ANGLE, REST_ANGLE } from '../../constants';
import Platter from './Platter';
import Tonearm from './Tonearm';
import { StartButton, SpeedSelector, StrobeLight, PitchSlider } from './Controls';

interface TurntableProps {
  currentTrack: Track | null;
  onTrackEnd: () => void;
}

const Turntable: React.FC<TurntableProps> = ({ currentTrack, onTrackEnd }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [armAngle, setArmAngle] = useState(REST_ANGLE);
  const [isCueUp, setIsCueUp] = useState(true); // Default to UP (Safe)
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  // Mouse position for lighting effects
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const animationRef = useRef<number>();
  const containerRef = useRef<HTMLDivElement>(null);

  // Handle Mouse Move for Specular Highlights
  const handleMouseMove = (e: React.MouseEvent) => {
      if (!containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const x = (e.clientX - rect.left) / rect.width;
      const y = (e.clientY - rect.top) / rect.height;
      setMousePos({ x, y });
  };

  // Audio Initialization
  useEffect(() => {
    if (currentTrack) {
        setAudioUrl(currentTrack.audioUrl);
        // Only reset if we are stopped, to avoid interrupting a flow
        if (!isPlaying) {
             setArmAngle(REST_ANGLE);
             setIsCueUp(true);
        }
    }
  }, [currentTrack]);

  // SYNC: Auto-Start / Auto-Return Logic
  useEffect(() => {
    if (isPlaying) {
        // If Play is pressed and arm is at rest, Move to Start
        if (Math.abs(armAngle - REST_ANGLE) < 2) {
            setArmAngle(START_ANGLE);
            setIsCueUp(false); // Drop the needle
        }
    } else {
        // If Stop is pressed, Return to Rest
        setArmAngle(REST_ANGLE);
        setIsCueUp(true);
    }
  }, [isPlaying]);

  // Audio Playback & Volume Logic
  useEffect(() => {
    if (!audioRef.current) return;

    // Logic: Music plays IF (isPlaying=TRUE) AND (Arm is on Record) AND (Cue is DOWN)
    const isNeedleOnRecord = armAngle >= START_ANGLE && armAngle <= END_ANGLE;
    // We allow a small buffer for the "groove" to catch
    const shouldPlay = isPlaying && isNeedleOnRecord && !isCueUp;

    if (shouldPlay) {
        audioRef.current.play().catch(e => console.log("Interaction needed", e));

        // Sync time
        const duration = audioRef.current.duration || 1;
        const progress = (armAngle - START_ANGLE) / (END_ANGLE - START_ANGLE);
        const targetTime = Math.max(0, Math.min(progress * duration, duration));

        if (Math.abs(audioRef.current.currentTime - targetTime) > 0.5) {
            audioRef.current.currentTime = targetTime;
        }
        audioRef.current.volume = 1.0;

    } else {
        audioRef.current.pause();
    }
  }, [isPlaying, armAngle, isCueUp]);

  // Animation Loop (Physics)
  useEffect(() => {
    let lastTime = performance.now();
    let currentVelocity = 0; 
    const maxVelocity = 3; // 33 RPM approx

    const animate = (time: number) => {
      const delta = time - lastTime;
      lastTime = time;

      // 1. Platter Rotation
      if (isPlaying) {
        currentVelocity = Math.min(currentVelocity + 0.1, maxVelocity); // Spin up
      } else {
        currentVelocity = Math.max(currentVelocity - 0.05, 0); // Spin down friction
      }

      if (currentVelocity > 0) {
          setRotation(prev => (prev + currentVelocity) % 360);
      }

      // 2. Tonearm Tracking (Visual only)
      if (currentVelocity > 2 && armAngle >= START_ANGLE && armAngle < END_ANGLE && !isCueUp) {
         if (audioRef.current && !audioRef.current.paused) {
             const duration = audioRef.current.duration || 180;
             const progress = audioRef.current.currentTime / duration;
             const newAngle = START_ANGLE + (progress * (END_ANGLE - START_ANGLE));
             setArmAngle(newAngle);

             if (progress >= 1) {
                 onTrackEnd();
             }
         }
      }

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
        if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying, armAngle, isCueUp, onTrackEnd]);

  // --- Handlers ---

  const handleDragStart = () => {
      setIsCueUp(true); // Lift arm when dragging
  };

  const handleDrag = (angle: number) => {
      setArmAngle(angle);
  };

  const handleDragEnd = () => {
      // Drop arm if on record
      if (armAngle >= START_ANGLE && armAngle <= END_ANGLE) {
          setIsCueUp(false);
          setIsPlaying(true); // Auto-start motor if dropped on record
      }
  };

  const handleCueToggle = (up: boolean) => {
      setIsCueUp(up);
  };

  return (
    <div 
        ref={containerRef} 
        onMouseMove={handleMouseMove}
        className="relative w-full max-w-4xl aspect-[3/2] select-none p-4"
        style={{ containerType: 'inline-size' }}
    >
       <audio ref={audioRef} src={audioUrl || ''} loop={false} />

       {/* THE MONOLITH (Main Chassis) */}
       <div className="relative w-full h-full shadow-[0_4cqw_8cqw_rgba(0,0,0,0.5),0_1cqw_2cqw_rgba(0,0,0,0.3)] rounded-[0.5cqw] overflow-hidden bg-[#2a0505] transform transition-transform hover:scale-[1.002]">

           {/* Brushed Metallic Burgundy Surface */}
           <div 
             className="absolute inset-0"
             style={{
                background: `
                    repeating-linear-gradient(90deg, transparent, transparent 1px, rgba(0,0,0,0.1) 1px, rgba(0,0,0,0.1) 2px),
                    linear-gradient(135deg, ${COLORS.plinthHighlight} 0%, ${COLORS.plinthBase} 100%)
                `,
                filter: 'contrast(1.1) brightness(0.9)',
             }}
           >
               {/* Specular Glare */}
               <div 
                 className="absolute inset-0 mix-blend-soft-light opacity-40 pointer-events-none"
                 style={{
                     background: `radial-gradient(circle at ${mousePos.x * 100}% ${mousePos.y * 100}%, rgba(255,255,255,0.4) 0%, transparent 60%)`
                 }}
               ></div>

               {/* Noise Grain */}
               <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] mix-blend-overlay"></div>

               {/* Branding */}
               <div className="absolute bottom-[5%] right-[12%] flex flex-col items-end opacity-80 z-10">
                    <span className="font-serif italic text-[#C5A059] text-[2.5cqw] drop-shadow-sm">Technics</span>
                    <span className="text-[0.6cqw] font-mono text-[#C5A059]/60 tracking-[0.2em] uppercase mt-0.5">Quartz Direct Drive Turntable System SL-1200MK2</span>
               </div>
           </div>

           {/* --- COMPONENTS --- */}

           {/* 1. Strobe Light (Top Left) */}
           <StrobeLight isPlaying={isPlaying} />

           {/* 2. Platter Assembly (Right side of Left Half) */}
           <div className="absolute top-[50%] left-[50%] w-[50%] h-auto aspect-square -translate-x-1/2 -translate-y-1/2 z-10">
                <Platter isPlaying={isPlaying} track={currentTrack} rotation={rotation} />
           </div>

           {/* 3. Tonearm Assembly */}
           {/* Arm Rest Post - Scalable */}
           <div className="absolute top-[55%] right-[20%] w-[1.5cqw] h-[4cqw] bg-neutral-900 rounded-[0.2cqw] shadow-lg border border-neutral-700 z-10 flex flex-col items-center justify-start py-[0.5cqw]">
                <div className="w-[1cqw] h-[1cqw] rounded-full bg-black/50 mb-[0.5cqw]"></div>
                <div className="w-full h-[0.1cqw] bg-neutral-700"></div>
           </div>

           <Tonearm 
             angle={armAngle}
             isShivering={isPlaying && armAngle > START_ANGLE && armAngle < END_ANGLE}
             onDragStart={handleDragStart}
             onDrag={handleDrag}
             onDragEnd={handleDragEnd}
             onCueToggle={handleCueToggle}
             isCueUp={isCueUp}
             parentRef={containerRef}
           />

           {/* 4. Power Block */}
           <StartButton isPlaying={isPlaying} onTogglePlay={() => setIsPlaying(!isPlaying)} />
           <SpeedSelector />

           {/* 5. Pitch Control */}
           <PitchSlider />

           {/* Power Dial */}
           <div className="absolute bottom-[20%] left-[3%] z-10">
              <div className="w-[4cqw] h-[4cqw] rounded-full bg-gradient-to-br from-neutral-700 to-neutral-900 border border-neutral-600 shadow-lg flex items-center justify-center">
                  <div className="w-[0.5cqw] h-[2cqw] bg-black rounded-full shadow-[inset_0_0_2px_rgba(255,255,255,0.2)] transform rotate-45"></div>
              </div>
              <div className="absolute top-full left-1/2 -translate-x-1/2 mt-[0.5cqw] text-[0.6cqw] text-neutral-500 font-mono tracking-widest whitespace-nowrap">OFF • ON</div>
           </div>

           {/* 45 Adapter Slot */}
           <div className="absolute top-[10%] right-[5%] w-[5cqw] h-[5cqw] rounded-full bg-black/40 shadow-inner border border-white/5 flex items-center justify-center">
               <div className="w-[4cqw] h-[4cqw] rounded-full bg-[#111] border border-neutral-700 shadow-[0_0.2cqw_0.5cqw_rgba(0,0,0,0.5)]"></div>
           </div>

       </div>
    </div>
  );
};

export default Turntable;

import React, { useState, useCallback } from 'react';
import { REST_ANGLE, START_ANGLE, END_ANGLE } from '../../constants';

interface TonearmProps {
  angle: number;
  isShivering: boolean;
  onDragStart: () => void;
  onDrag: (angle: number) => void;
  onDragEnd: () => void;
  onCueToggle: (isUp: boolean) => void; 
  isCueUp: boolean;
  parentRef: React.RefObject<HTMLDivElement>;
}

const Tonearm: React.FC<TonearmProps> = ({ 
  angle, 
  isShivering, 
  onDragStart, 
  onDrag, 
  onDragEnd, 
  onCueToggle,
  isCueUp,
  parentRef 
}) => {
  const [isDragging, setIsDragging] = useState(false);

  // Pivot point percentages relative to the 3:2 container
  const PIVOT_X_PCT = 80;
  const PIVOT_Y_PCT = 30;

  const calculateAngle = useCallback((clientX: number, clientY: number) => {
    if (!parentRef.current) return 0;

    const parentRect = parentRef.current.getBoundingClientRect();
    const pivotX = parentRect.left + (parentRect.width * (PIVOT_X_PCT / 100));
    const pivotY = parentRect.top + (parentRect.height * (PIVOT_Y_PCT / 100));

    const dx = clientX - pivotX;
    const dy = clientY - pivotY;

    let theta = Math.atan2(dy, dx) * (180 / Math.PI);
    return theta;
  }, [parentRef]);

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    setIsDragging(true);
    onDragStart();
    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    const newAngle = calculateAngle(e.clientX, e.clientY);
    const clampedAngle = Math.max(REST_ANGLE - 5, Math.min(newAngle, END_ANGLE + 15));
    onDrag(clampedAngle);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    setIsDragging(false);
    onDragEnd();
    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  return (
    <>
      {/* BASE MECHANISM (Fixed on Plinth) */}
      <div 
        className="absolute z-20 pointer-events-none"
        style={{ top: `${PIVOT_Y_PCT}%`, left: `${PIVOT_X_PCT}%` }}
      >
           {/* Gimbal Base Ring */}
           <div className="absolute top-0 left-0 -translate-x-1/2 -translate-y-1/2 w-[16cqw] aspect-square rounded-full bg-[#151515] border-[0.2cqw] border-[#222] shadow-[0_1cqw_2cqw_rgba(0,0,0,0.6)]"></div>

           {/* Anti-Skate Dial */}
           <div className="absolute top-[25%] right-[-30%] w-[5cqw] aspect-square rounded-full bg-[#1a1a1a] border border-neutral-700 shadow-lg flex items-center justify-center">
               <div className="w-[80%] h-[80%] rounded-full border border-neutral-600 bg-gradient-to-tr from-neutral-800 to-neutral-700 flex items-center justify-center text-[0.6cqw] text-neutral-400 font-mono">
                  2.5
               </div>
           </div>

           {/* CUE LEVER (Interactable) */}
           <div 
              className="absolute top-[18%] right-[-12%] z-30 pointer-events-auto cursor-pointer group"
              onClick={() => onCueToggle(!isCueUp)}
           >
                {/* Lever Base */}
                <div className="w-[4cqw] aspect-square rounded-full bg-[#111] border border-neutral-700 flex items-center justify-center shadow-md">
                     {/* The Lever Arm */}
                     <div 
                        className="w-[10%] h-[140%] bg-gradient-to-b from-[#8F7124] to-[#D4AF37] rounded-full origin-bottom transition-transform duration-500 ease-in-out shadow-sm"
                        style={{ transform: isCueUp ? 'rotate(-10deg) translateY(-10%)' : 'rotate(45deg)' }}
                     >
                        {/* Lever Tip */}
                        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[200%] h-[30%] bg-black rounded-full"></div>
                     </div>
                </div>
           </div>
      </div>

      {/* ROTATING TONEARM ASSEMBLY */}
      <div 
        className="absolute z-30 w-[32%] aspect-[32/10] origin-top-left"
        style={{ 
          top: `${PIVOT_Y_PCT}%`,
          left: `${PIVOT_X_PCT}%`,
          transform: `rotate(${angle}deg)`,
          transition: isDragging ? 'none' : 'transform 1.0s cubic-bezier(0.2, 1.0, 0.5, 1)', 
          touchAction: 'none',
          cursor: isDragging ? 'grabbing' : 'grab',
          filter: isCueUp ? 'drop-shadow(0.5cqw 0.5cqw 0.5cqw rgba(0,0,0,0.5))' : 'none'
        }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        <div className={`relative w-full h-full pointer-events-none ${isShivering && !isCueUp ? 'animate-shiver' : ''}`}>

          {/* Main Bearing Housing (Yoke) */}
          <div className="absolute -top-[7.5%] -left-[7.5%] w-[15%] aspect-square rounded-full border-[0.6cqw] border-[#1a1a1a] z-30 border-t-transparent rotate-45"></div>
          <div className="absolute -top-[4.5%] -left-[4.5%] w-[9%] aspect-square rounded-full bg-gradient-to-br from-[#333] to-black border border-neutral-700 z-30 shadow-lg"></div>

          {/* Counterweight */}
          <div className="absolute top-[-1.5%] left-[-26%] w-[25%] h-[32%] z-10">
             <div className="w-full h-full bg-gradient-to-b from-[#2a2a2a] via-[#444] to-[#2a2a2a] rounded-[0.2cqw] border border-neutral-700 shadow-md flex items-center relative">
                 <div className="absolute inset-y-0 left-[20%] w-[1px] bg-black/50"></div>
                 <div className="absolute inset-y-0 left-[25%] w-[1px] bg-black/50"></div>
                 {/* Brass End Cap */}
                 <div className="absolute right-0 top-0 bottom-0 w-[5%] bg-[#8F7124] rounded-r-[0.2cqw]"></div>
             </div>
          </div>

          {/* Brass S-Curve Arm (SVG) */}
          <svg 
              viewBox="0 0 300 100" 
              className="absolute top-[-2.5%] left-[3%] w-full h-full overflow-visible drop-shadow-lg z-20"
              preserveAspectRatio="xMinYMid meet"
              style={{ pointerEvents: 'none' }}
          >
              <defs>
                  <linearGradient id="brassGradient" x1="0%" y1="0%" x2="0%" y2="100%">
                      <stop offset="0%" stopColor="#8F7124" />
                      <stop offset="40%" stopColor="#D4AF37" />
                      <stop offset="60%" stopColor="#D4AF37" />
                      <stop offset="100%" stopColor="#8F7124" />
                  </linearGradient>
              </defs>
              <path 
                  d="M 0,8 L 112,8 C 152,8 160,25 192,25 L 208,25 C 224,25 232,12 240,12" 
                  fill="none" 
                  stroke="url(#brassGradient)" 
                  strokeWidth="10" 
                  strokeLinecap="butt"
              />
          </svg>

          {/* Headshell */}
          <div 
              className="absolute z-30 pointer-events-auto hover:scale-105 transition-transform"
              style={{ 
                  left: '79%', 
                  top: '-3%',
                  width: '20%',
                  height: '24%',
                  transform: 'rotate(-18deg)', 
                  transformOrigin: 'left center'
              }}
          >
              <div className="w-full h-full bg-[#111] rounded-[0.1cqw] border border-neutral-700 shadow-xl relative">
                  {/* Finger Lift */}
                  <div className="absolute right-[-6%] top-[15%] w-[60%] h-[15%] bg-[#222] rounded-full origin-left rotate-[-20deg] shadow-sm border border-neutral-800"></div>

                  {/* Gold Screws */}
                  <div className="absolute top-[30%] left-[25%] w-[10%] aspect-square rounded-full bg-[#D4AF37] shadow-sm"></div>
                  <div className="absolute top-[30%] left-[50%] w-[10%] aspect-square rounded-full bg-[#D4AF37] shadow-sm"></div>
              </div>
          </div>

        </div>
      </div>
    </>
  );
};

