        */}
        <div 
            className={`relative w-full h-full transition-all duration-700 ease-in-out ${isShivering ? 'animate-shiver' : ''}`}
            style={{
                transform: isCueUp ? 'scale(1.05) translateY(-2%)' : 'scale(1.0) translateY(0)',
                filter: isCueUp 
