    onSetRpm: (rpm: 33 | 45) => void;
}

export const SpeedSelector: React.FC<SpeedSelectorProps> = ({ currentRpm, onSetRpm }) => {
    return (
        <div className="absolute top-[85%] left-[22%] -translate-y-1/2 flex gap-[1cqw] z-50">
            {[33, 45].map((speed) => (
                <button 
                    key={speed}
                    onClick={(e) => {
                        e.stopPropagation();
                        onSetRpm(speed as 33 | 45);
                    }}
                    className={`w-[4cqw] aspect-[5/4] rounded-[0.2cqw] bg-[#1a1a1a] border border-black shadow-[0_0.2cqw_0.4cqw_rgba(0,0,0,0.5)] flex items-center justify-center active:translate-y-[2%] cursor-pointer ${currentRpm === speed ? 'ring-[0.1cqw] ring-red-900/50' : ''}`}
                >
                    <span className={`text-[1cqw] font-mono ${currentRpm === speed ? 'text-red-500 shadow-[0_0_0.5cqw_rgba(255,0,0,0.2)]' : 'text-neutral-600'}`}>{speed}</span>
                </button>
            ))}
        </div>
    );
};

