interface RotaryKnobProps {
    value: number; // 0 to 1
    onChange: (value: number) => void;
    label: string;
    indicatorColor?: string;
}

export const RotaryKnob: React.FC<RotaryKnobProps> = ({ value, onChange, label, indicatorColor = '#22d3ee' }) => {
    const [isDragging, setIsDragging] = useState(false);
    const [startY, setStartY] = useState(0);
    const [startValue, setStartValue] = useState(0);

    const handleMouseDown = (e: React.MouseEvent) => {
        setIsDragging(true);
        setStartY(e.clientY);
        setStartValue(value);
        document.body.style.cursor = 'ns-resize';
    };

    const handleMouseMove = useCallback((e: MouseEvent) => {
        if (!isDragging) return;
        const deltaY = startY - e.clientY; 
        const sensitivity = 0.005;
        const newValue = Math.min(1, Math.max(0, startValue + (deltaY * sensitivity)));
        onChange(newValue);
    }, [isDragging, startY, startValue, onChange]);

    const handleMouseUp = useCallback(() => {
        setIsDragging(false);
        document.body.style.cursor = 'default';
    }, []);

    useEffect(() => {
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        } else {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging, handleMouseMove, handleMouseUp]);

    const rotation = -135 + (value * 270);

    return (
        <div className="flex flex-col items-center gap-[0.5cqw] select-none z-50">
            <div 
                className="relative w-[5cqw] aspect-square rounded-full bg-gradient-to-br from-[#2a2a2a] to-[#111] shadow-[0_0.5cqw_1cqw_rgba(0,0,0,0.6),inset_0_0.1cqw_0.1cqw_rgba(255,255,255,0.1)] border border-neutral-800 cursor-ns-resize"
                onMouseDown={handleMouseDown}
            >
                <div className="absolute inset-0 rounded-full opacity-30" 
                     style={{ 
                         background: 'repeating-conic-gradient(#000 0deg, #000 2deg, transparent 2deg, transparent 4deg)' 
                     }}>
                </div>

                <div className="absolute inset-[10%] rounded-full bg-gradient-to-br from-[#333] to-[#1a1a1a] shadow-inner border border-neutral-700 flex items-center justify-center"
                     style={{ transform: `rotate(${rotation}deg)` }}
                >
                    <div className="absolute top-[10%] w-[10%] h-[40%] rounded-full"
                         style={{ backgroundColor: indicatorColor, boxShadow: `0 0 2px ${indicatorColor}` }}
                    ></div>
                </div>
            </div>
            <span className="text-[0.5cqw] text-neutral-500 font-mono tracking-widest uppercase">{label}</span>
        </div>
    );
};


