                    <div className="absolute left-1/2 -translate-x-1/2 w-[300%] aspect-[2/3] rounded-[0.1cqw] shadow-xl flex items-center justify-center group z-20 pointer-events-none"
                        style={{
                            top: `${50 - (value * 5)}%`, 
                            background: `linear-gradient(to bottom, ${COLORS.goldDark}, ${COLORS.gold} 20%, ${COLORS.goldDark})`,
                            border: '0.1cqw solid #634d1b',
                            transform: 'translate(-50%, -50%)'
                        }}
                    >
                        <div className="w-full h-[0.1cqw] bg-black/40"></div>
                    </div>
                </div>

                <div className={`absolute top-1/2 right-[-20%] w-[15%] aspect-square rounded-full -translate-y-1/2 shadow-[inset_0_0_1px_rgba(0,0,0,1)] transition-colors duration-200 ${Math.abs(value) < 0.5 ? 'bg-green-500 shadow-[0_0_5px_#22c55e]' : 'bg-green-900'}`}></div>
            </div>

            {/* QUARTZ LOCK */}
            <div className="absolute right-[3%] top-[45%] z-50 flex flex-col items-center">
                <button 
                    onClick={(e) => {
                        e.stopPropagation();
                        onChange(0);
