                    className="w-[3.5cqw] aspect-square rounded-full bg-gradient-to-br from-[#1a1a1a] to-[#0d0d0d] border border-neutral-700 shadow-[0_0.2cqw_0.4cqw_rgba(0,0,0,0.8),inset_0_0.1cqw_0.1cqw_rgba(255,255,255,0.1)] flex items-center justify-center cursor-pointer active:scale-95 group transition-transform"
                    title="Quartz Lock / Pitch Reset"
                >
                    <div className={`w-[0.8cqw] aspect-square rounded-full shadow-[inset_0_0_1px_rgba(0,0,0,0.5)] transition-all duration-300 ${value === 0 ? 'bg-green-500 shadow-[0_0_4px_#22c55e]' : 'bg-green-900'}`}></div>
                </button>
                <span className="mt-[0.5cqw] text-[0.5cqw] text-neutral-500 font-mono tracking-widest">RESET</span>
            </div>
        </>
    )
}

interface RotaryKnobProps {
    value: number; // 0 to 1
    onChange: (value: number) => void;
    label: string;
    indicatorColor?: string;
    onInteract?: () => void;
}

export const RotaryKnob: React.FC<RotaryKnobProps> = ({ value, onChange, label, indicatorColor = '#22d3ee', onInteract }) => {
    const [isDragging, setIsDragging] = useState(false);
    const [startY, setStartY] = useState(0);
    const [startValue, setStartValue] = useState(0);

    const handleMouseDown = (e: React.MouseEvent) => {
        setIsDragging(true);
        setStartY(e.clientY);
        setStartValue(value);
        document.body.style.cursor = 'ns-resize';
        if(onInteract) onInteract();
    };

    const handleMouseMove = useCallback((e: MouseEvent) => {
        if (!isDragging) return;
        const deltaY = startY - e.clientY; 
        const sensitivity = 0.005;
        const newValue = Math.min(1, Math.max(0, startValue + (deltaY * sensitivity)));
        onChange(newValue);
    }, [isDragging, startY, startValue, onChange]);

    const handleMouseUp = useCallback(() => {
        setIsDragging(false);
        document.body.style.cursor = 'default';
    }, []);

    useEffect(() => {
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        } else {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging, handleMouseMove, handleMouseUp]);

    const rotation = -135 + (value * 270);

    return (
        <div className="flex flex-col items-center gap-[0.5cqw] select-none z-50">
            {/* Arched Label above */}
            <span className="text-[0.7cqw] text-neutral-300 font-bold font-sans tracking-widest uppercase mb-[0.5cqw] drop-shadow-md">{label}</span>

            <div 
                className="relative w-[7cqw] aspect-square rounded-full shadow-[0_1cqw_2cqw_rgba(0,0,0,0.8),inset_0_0.2cqw_0.5cqw_rgba(255,255,255,0.2)] cursor-ns-resize"
                style={{
                    background: 'conic-gradient(from 0deg, #111, #333 45%, #111 90%, #222)',
                    border: '0.15cqw solid #444'
                }}
                onMouseDown={handleMouseDown}
            >
                {/* Knurled Pattern Effect */}
                <div className="absolute inset-0 rounded-full opacity-50" 
                     style={{ 
                         background: 'repeating-conic-gradient(#000 0deg, #000 2deg, transparent 2deg, transparent 4deg)' 
                     }}>
                </div>

                {/* Top Cap */}
                <div className="absolute inset-[10%] rounded-full bg-gradient-to-br from-[#2a2a2a] to-[#050505] shadow-[inset_0_1px_1px_rgba(255,255,255,0.1)] border border-neutral-900 flex items-center justify-center"
                     style={{ transform: `rotate(${rotation}deg)` }}
                >
                    {/* Teal Indicator Line / Notch */}
                    <div className="absolute top-[5%] w-[8%] h-[35%] rounded-full shadow-[0_0_4px_rgba(34,211,238,0.5)]"
                         style={{ backgroundColor: indicatorColor }}
                    ></div>
                </div>
            </div>
        </div>
    );
};


