const Turntable: React.FC<TurntableProps> = ({ currentTrack, onTrackEnd, activeSubTrackIndex, onSubTrackChange }) => {
  const [isPowerOn, setIsPowerOn] = useState(true);
  const [isPlaying, setIsPlaying] = useState(false); // Acts as Motor Start/Stop
  const [rotation, setRotation] = useState(0);
  const [armAngle, setArmAngle] = useState(REST_ANGLE);
  const [isCueUp, setIsCueUp] = useState(true); // Default to UP (Safe)
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  // Hardware State
  const [rpm, setRpm] = useState<33 | 45>(33);
  const [pitch, setPitch] = useState(0); // -8 to 8
  const [showHints, setShowHints] = useState(false);
  const [masterVolume, setMasterVolume] = useState(1.0);
  const [vintageLevel, setVintageLevel] = useState(0.25);

  // Transition State Management
  const [displayTrack, setDisplayTrack] = useState<Track | null>(currentTrack);
  const [platterSlideState, setPlatterSlideState] = useState<'center' | 'left' | 'right'>('center');
  const [isTransitioning, setIsTransitioning] = useState(false);

  // Mouse position for lighting effects
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const crackleRef = useRef<HTMLAudioElement | null>(null);
  const humRef = useRef<HTMLAudioElement | null>(null);
  const animationRef = useRef<number>();
  const containerRef = useRef<HTMLDivElement>(null);
  const soundsRef = useRef<{[key: string]: HTMLAudioElement}>({});

  // --- SOUND ENGINE ---
  useEffect(() => {
    // Initialize sound effects
    const soundFiles = {
        thunk: 'heavy-thunk.mp3', // Updated to Heavy Thunk
        click: 'click.mp3',
        clunk: 'mechanical-clunk.mp3', // For Start Button layer
        potentiometer: 'potentiometer-click.mp3'
    };

    // In a real app, we would load these. For now, we mock the ref so code doesn't crash.
    Object.entries(soundFiles).forEach(([key, file]) => {
        soundsRef.current[key] = new Audio(file);
        soundsRef.current[key].volume = 0.6;
    });
  }, []);

  const playSound = (type: string) => {
      // Logic to play sound if it existed
      const sound = soundsRef.current[type];
      if (sound) {
          sound.currentTime = 0;
          sound.play().catch(() => {}); // Ignore errors if file missing
      }
  };

  // Handle Mouse Move for Specular Highlights
  const handleMouseMove = (e: React.MouseEvent) => {
      if (!containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const x = (e.clientX - rect.left) / rect.width;
      const y = (e.clientY - rect.top) / rect.height;
      setMousePos({ x, y });
  };

  // --- POWER SWITCH LOGIC ---
  useEffect(() => {
    if (!isPowerOn) {
        setIsPlaying(false); // Stop Motor
        // Auto-Return Arm
        if (Math.abs(armAngle - REST_ANGLE) > 2) {
             setIsCueUp(true);
             const returnTimer = setTimeout(() => {
                 setArmAngle(REST_ANGLE);
             }, 300);
             return () => clearTimeout(returnTimer);
        }
    }
  }, [isPowerOn, armAngle]);

  // --- SUB-TRACK NAVIGATION (Quick Sweep) ---
  useEffect(() => {
    if (activeSubTrackIndex >= 0 && currentTrack?.tracklist) {
        // Calculate groove coordinate
        const totalTracks = currentTrack.tracklist.length;
        // Map index to angle range (Start to End)
        // We leave a bit of buffer at the start/end
        const grooveSpan = END_ANGLE - START_ANGLE;
        const segment = grooveSpan / totalTracks;
        const targetAngle = START_ANGLE + (segment * activeSubTrackIndex) + (segment * 0.1); // +10% into the track

        // Trigger "Quick Sweep"
        // 1. Lift Arm
        setIsCueUp(true);

        // 2. Move (timeout to allow lift visual)
        setTimeout(() => {
            setArmAngle(targetAngle);
            // 3. Drop (timeout to allow move)
            if (isPowerOn && isPlaying && !isTransitioning) {
                 setTimeout(() => {
                     setIsCueUp(false);
                 }, 400);
            }
        }, 300);

        // Update Audio Time
        if (audioRef.current && currentTrack.duration) {
             const timeSegment = currentTrack.duration / totalTracks;
             audioRef.current.currentTime = timeSegment * activeSubTrackIndex;
        }
    }
  }, [activeSubTrackIndex, currentTrack, isPowerOn, isPlaying, isTransitioning]);

  const handleSkip = (dir: 1 | -1) => {
      if (!currentTrack?.tracklist) return;
      playSound('click');
      onSubTrackChange(prev => {
          const next = prev + dir;
          return Math.max(0, Math.min(next, currentTrack.tracklist!.length - 1));
      });
  };

  // --- ALBUM SWAP SEQUENCE (Ghost Vinyl Fix) ---
  useEffect(() => {
    if (currentTrack?.id !== displayTrack?.id) {
        setIsTransitioning(true);

        // Step 1: Retract Arm
        setArmAngle(REST_ANGLE);
        setIsCueUp(true);

        // Step 2: Slide Out Old Disc
        const ejectTimer = setTimeout(() => {
            setPlatterSlideState('left');
        }, 400);

        // Step 3: Load Asset & Swap
        const swapTimer = setTimeout(() => {
            // Start loading new image
            const img = new Image();
            img.src = currentTrack?.coverArt || '';

            img.onload = () => {
                // Only proceed once loaded
                setDisplayTrack(currentTrack);
                setPlatterSlideState('right'); // Teleport hidden
                setAudioUrl(currentTrack?.audioUrl || null);

                // Step 4: Slide In New Disc (Short delay after render)
                setTimeout(() => {
                    setPlatterSlideState('center');

                    // Step 5: Finish
                    setTimeout(() => {
                        setIsTransitioning(false);
                        if (isPowerOn && isPlaying) {
                             setArmAngle(START_ANGLE);
                             setIsCueUp(false);
                        }
                    }, 500);
                }, 50);
            };
        }, 900);

        return () => {
            clearTimeout(ejectTimer);
            clearTimeout(swapTimer);
        };
    }
  }, [currentTrack, displayTrack, isPlaying, isPowerOn]);


  // Auto-Start
  useEffect(() => {
    if (isTransitioning || !isPowerOn) return; 

    if (isPlaying) {
        if (Math.abs(armAngle - REST_ANGLE) < 2) {
            setArmAngle(START_ANGLE);
            setIsCueUp(false); 
        }
    }
  }, [isPlaying, isTransitioning, isPowerOn]);

  // Audio Playback Engine
  useEffect(() => {
    if (!audioRef.current || !crackleRef.current || !humRef.current) return;

    if (!isPowerOn) {
        audioRef.current.pause();
        crackleRef.current.pause();
        humRef.current.pause();
        return;
    }

    // Pitch & Speed Logic
    const baseRate = rpm === 45 ? 1.35 : 1.0;
    const pitchFactor = 1 + (pitch / 100); 
    const playbackRate = Math.max(0.1, baseRate * pitchFactor);

    audioRef.current.playbackRate = playbackRate;
    crackleRef.current.playbackRate = playbackRate;

    // --- MAIN MUSIC LOGIC ---
    const isNeedleOnRecord = armAngle >= START_ANGLE && armAngle <= END_ANGLE;
    const shouldPlayMusic = isPlaying && isNeedleOnRecord && !isCueUp && !isTransitioning;

    if (shouldPlayMusic) {
        audioRef.current.play().catch(e => console.log("Interaction needed", e));

        // Sync visual position to audio time
        const duration = audioRef.current.duration || 1;
        const progress = (armAngle - START_ANGLE) / (END_ANGLE - START_ANGLE);
        const targetTime = Math.max(0, Math.min(progress * duration, duration));

        if (Math.abs(audioRef.current.currentTime - targetTime) > 2.0) {
            audioRef.current.currentTime = targetTime;
        }
        audioRef.current.volume = masterVolume; 
    } else {
        audioRef.current.pause();
    }

    // --- VINTAGE CRACKLE LOGIC ---
    // Crackle plays if Motor ON (regardless of arm position)
    if (isPlaying && !isTransitioning) {
        crackleRef.current.play().catch(() => {});
        crackleRef.current.volume = vintageLevel * masterVolume; 

        // --- MOTOR HUM LOGIC ---
        humRef.current.play().catch(() => {});
        humRef.current.volume = 0.15; // Low hum
    } else {
        crackleRef.current.pause();
        humRef.current.pause();
    }

  }, [isPlaying, armAngle, isCueUp, isTransitioning, rpm, pitch, masterVolume, vintageLevel, isPowerOn]);

  // Animation Loop
  useEffect(() => {
    let lastTime = performance.now();
    let currentVelocity = 0; 

    const baseVelocity = rpm === 45 ? 4.5 : 3.3; 

    const animate = (time: number) => {
      const delta = time - lastTime;
      lastTime = time;
      const velocityTarget = baseVelocity * (1 + (pitch/100));

      if (isPowerOn && isPlaying && !isTransitioning) {
        currentVelocity = Math.min(currentVelocity + 0.1, velocityTarget); 
      } else {
        currentVelocity = Math.max(currentVelocity - 0.05, 0); 
      }

      if (currentVelocity > 0) {
          setRotation(prev => (prev + currentVelocity) % 360);
      }

      // Tonearm Inward Sweep (Visual)
      if (currentVelocity > 2 && armAngle >= START_ANGLE && armAngle < END_ANGLE && !isCueUp && !isTransitioning) {
         if (audioRef.current && !audioRef.current.paused) {
             const duration = audioRef.current.duration || 180;
             const progress = audioRef.current.currentTime / duration;
             const newAngle = START_ANGLE + (progress * (END_ANGLE - START_ANGLE));
             setArmAngle(newAngle);

             if (progress >= 1) {
                 onTrackEnd();
             }
         }
      }

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
        if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying, armAngle, isCueUp, onTrackEnd, isTransitioning, rpm, pitch, isPowerOn]);

  // --- Handlers ---

  const handleDragStart = () => {
      if (isTransitioning || !isPowerOn) return;
      setIsCueUp(true); 
  };

  const handleDrag = (angle: number) => {
      if (isTransitioning || !isPowerOn) return;
      setArmAngle(angle);
  };

  const handleDragEnd = () => {
      if (isTransitioning || !isPowerOn) return;
      if (armAngle >= START_ANGLE && armAngle <= END_ANGLE) {
          setIsCueUp(false);
          setIsPlaying(true); 
      }
  };

  const handleCueToggle = (up: boolean) => {
      if (isTransitioning || !isPowerOn) return;
      setIsCueUp(up);
      playSound('click');
  };

  return (
    <div 
        ref={containerRef} 
        onMouseMove={handleMouseMove}
        className="relative w-full max-w-4xl aspect-[3/2] select-none p-4"
        style={{ containerType: 'inline-size' }}
    >
       <audio ref={audioRef} src={audioUrl || ''} loop={false} />
       <audio ref={crackleRef} src="https://upload.wikimedia.org/wikipedia/commons/b/bb/Vinyl_crackle.ogg" loop={true} />
       <audio ref={humRef} src="https://upload.wikimedia.org/wikipedia/commons/6/61/60Hz_hum.ogg" loop={true} />

       {/* THE MONOLITH (Main Chassis) */}
       <div className="relative w-full h-full shadow-[0_4cqw_8cqw_rgba(0,0,0,0.5),0_1cqw_2cqw_rgba(0,0,0,0.3)] rounded-[0.5cqw] overflow-hidden bg-[#2a0505] transform transition-transform hover:scale-[1.002]">

           {/* Brushed Metallic Burgundy Surface */}
           <div 
             className="absolute inset-0"
             style={{
                background: `
                    repeating-linear-gradient(90deg, transparent, transparent 1px, rgba(0,0,0,0.1) 1px, rgba(0,0,0,0.1) 2px),
                    linear-gradient(135deg, ${COLORS.plinthHighlight} 0%, ${COLORS.plinthBase} 100%)
                `,
                filter: isPowerOn ? 'contrast(1.1) brightness(0.9)' : 'contrast(1.0) brightness(0.6) grayscale(0.5)', // Cold look when OFF
                transition: 'filter 0.5s ease'
             }}
           >
               {/* Specular Glare */}
               <div 
                 className="absolute inset-0 mix-blend-soft-light opacity-40 pointer-events-none"
                 style={{
                     background: `radial-gradient(circle at ${mousePos.x * 100}% ${mousePos.y * 100}%, rgba(255,255,255,0.4) 0%, transparent 60%)`
                 }}
               ></div>

               {/* Noise Grain */}
               <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] mix-blend-overlay"></div>

               {/* Branding */}
               <div className="absolute top-[85%] left-[50%] -translate-x-1/2 flex flex-col items-center opacity-80 z-10 pointer-events-none">
                    <span className="font-serif italic text-[#C5A059] text-[2.5cqw] drop-shadow-sm">Technics</span>
               </div>
           </div>

           {/* --- COMPONENTS --- */}

           {/* 1. Strobe Light (Adjusted Position) */}
           <StrobeLight isPlaying={isPlaying} isPowerOn={isPowerOn} />

           {/* 2. Platter Assembly */}
           <div className="absolute top-[50%] left-[50%] w-[50%] h-auto aspect-square -translate-x-1/2 -translate-y-1/2 z-10">
                <Platter 
                    isPlaying={isPlaying && isPowerOn} 
                    track={displayTrack} 
                    rotation={rotation}
                    slideState={platterSlideState}
                />
           </div>

           {/* 3. Tonearm Assembly */}
           <div className="absolute top-[55%] right-[20%] w-[1.5cqw] h-[4cqw] bg-neutral-900 rounded-[0.2cqw] shadow-lg border border-neutral-700 z-30 flex flex-col items-center justify-start py-[0.5cqw]">
                <div className="w-[1cqw] h-[1cqw] rounded-full bg-black/50 mb-[0.5cqw]"></div>
                <div className="w-full h-[0.1cqw] bg-neutral-700"></div>
           </div>

           <Tonearm 
             angle={armAngle}
             isShivering={isPowerOn && isPlaying && armAngle > START_ANGLE && armAngle < END_ANGLE && !isCueUp}
             onDragStart={handleDragStart}
             onDrag={handleDrag}
             onDragEnd={handleDragEnd}
             onCueToggle={handleCueToggle}
             isCueUp={isCueUp}
             parentRef={containerRef}
           />

           {/* 4. Controls */}
           <StartButton 
             isPlaying={isPlaying} 
             onTogglePlay={() => setIsPlaying(!isPlaying)} 
             isPowerOn={isPowerOn} 
             onInteract={() => {
                 playSound('click');
                 playSound('clunk'); // Layered sound
             }}
           />
           <SpeedSelector currentRpm={rpm} onSetRpm={setRpm} isPowerOn={isPowerOn} />
           <PitchSlider value={pitch} onChange={setPitch} />

           {/* GRAND POWER SWITCH (Now at Bottom Left Cluster via Controls.tsx) */}
           <PowerSwitch 
             isOn={isPowerOn} 
             onToggle={() => {
                 setIsPowerOn(!isPowerOn);
                 playSound('thunk'); // Heavy thunk
             }} 
            />

           <NavigationCluster onSkip={handleSkip} isPowerOn={isPowerOn} onInteract={() => playSound('click')} />

           {/* NEW: DUAL POTENTIOMETER CLUSTER (Bottom Center) */}
           <div className="absolute bottom-[4%] left-[50%] -translate-x-1/2 flex gap-[4cqw] z-50 bg-[#111]/30 p-[1cqw] rounded-full border border-white/5 backdrop-blur-sm shadow-xl">
                <RotaryKnob 
                    value={masterVolume} 
                    onChange={setMasterVolume} 
                    label="Volume" 
                    indicatorColor="#22d3ee" // Teal
                    onInteract={() => playSound('potentiometer')}
                />
                <RotaryKnob 
                    value={vintageLevel} 
                    onChange={setVintageLevel} 
                    label="Vintage" 
                    indicatorColor="#d97706" // Amber
                    onInteract={() => playSound('potentiometer')}
                />
           </div>

           {/* 45 Adapter Slot */}
           <div className="absolute top-[10%] right-[5%] w-[5cqw] h-[5cqw] rounded-full bg-black/40 shadow-inner border border-white/5 flex items-center justify-center">
               <div className="w-[4cqw] h-[4cqw] rounded-full bg-[#111] border border-neutral-700 shadow-[0_0.2cqw_0.5cqw_rgba(0,0,0,0.5)]"></div>
           </div>

           {/* HINTS */}
           {showHints && <HintOverlay />}
           <HelpButton active={showHints} onToggle={() => setShowHints(!showHints)} />

       </div>
    </div>
  );
};

