                <div className="absolute top-[10%] right-[140%] text-[0.6cqw] text-neutral-600 font-mono text-right leading-loose select-none flex flex-col justify-between h-[80%]">
                    <div>+8</div>
                    <div className="text-neutral-400">0</div>
                    <div>-8</div>
