  return (
    <div className={`w-full h-auto flex flex-col justify-center animate-fade-in transition-all duration-1000 ${isPowerOn ? 'opacity-100 filter-none' : 'opacity-20 blur-[1px] grayscale pointer-events-none'}`}>
