  calibrationOffset?: number; // Manual override for needle drop angle (degrees)
}

export enum PlayState {
  STOPPED = 'STOPPED',
  SPINNING_UP = 'SPINNING_UP',
  PLAYING = 'PLAYING',
  SPINNING_DOWN = 'SPINNING_DOWN'
}

export interface TurntableState {
  isPlaying: boolean;
