  volume: number;
}

import { Album } from '../types';
import { fetchCrateFromDrive } from './drive';

const STORAGE_KEY = 'studio_deck_master_crate_v1';

export const StorageService = {
  // Load Crate from LocalStorage or Fallback to Mock Drive
  async loadCrate(): Promise<Album[]> {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) {
        return JSON.parse(stored);
      }
      // Cold start: Fetch default mock data and save it
      const defaults = await fetchCrateFromDrive();
      this.saveCrate(defaults);
      return defaults;
    } catch (e) {
      console.error("Storage Load Failed", e);
      return [];
    }
  },

  // Save Crate to LocalStorage
  saveCrate(crate: Album[]) {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(crate));
    } catch (e) {
      console.error("Storage Save Failed", e);
    }
  },

  // Add a new Album (Simulated Drive Scrape)
  async addAlbumFromFolderId(folderId: string): Promise<Album> {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Return a mock object based on the ID
    const newAlbum: Album = {
      id: folderId,
      title: `Imported Folder ${folderId.substring(0, 4)}`,
      artist: 'Unknown Artist',
      coverArt: `https://picsum.photos/seed/${folderId}/600/600`, // Deterministic random image
