import React, { useState, useEffect } from 'react';
import { AlertTriangle, Lock } from 'lucide-react';

interface AuthModalProps {
  isOpen: boolean;
  onSuccess: () => void;
  onClose: () => void;
}

const AuthModal: React.FC<AuthModalProps> = ({ isOpen, onSuccess, onClose }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const [shake, setShake] = useState(false);

  useEffect(() => {
      if (isOpen) {
          setPassword('');
          setError(false);
      }
  }, [isOpen]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'r1ckyBoy2') {
        onSuccess();
    } else {
        // Short Circuit Effect
        setError(true);
        setShake(true);
        setTimeout(() => {
            setShake(false);
            onClose(); // Boot them out
        }, 1000);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-fade-in">
        <form 
            onSubmit={handleSubmit}
            className={`
                bg-[#111] border-2 border-red-900/50 p-8 rounded-lg shadow-[0_0_50px_rgba(255,0,0,0.2)]
                flex flex-col items-center gap-4 w-[300px]
                ${shake ? 'animate-shake border-red-500' : ''}
            `}
        >
            <div className="text-red-600 mb-2">
                {error ? <AlertTriangle className="w-12 h-12 animate-pulse" /> : <Lock className="w-12 h-12" />}
            </div>

            <h2 className="text-red-500 font-mono tracking-widest text-sm uppercase">Restricted Access</h2>

            <input 
                type="password" 
                autoFocus
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="bg-black border border-red-900 text-red-500 font-mono text-center tracking-[0.5em] p-2 outline-none focus:border-red-500 w-full rounded"
                placeholder="ACCESS CODE"
            />

            {error && <div className="text-red-500 font-mono text-xs animate-pulse">SYSTEM SHORT CIRCUIT</div>}
        </form>
    </div>
  );
};

