const ASSETS = {
    power: 'https://assets.mixkit.co/active_storage/sfx/2568/2568-preview.mp3', // Heavy Switch
    click: 'https://assets.mixkit.co/active_storage/sfx/2573/2573-preview.mp3', // Mechanical Click
    knob: 'https://assets.mixkit.co/active_storage/sfx/2580/2580-preview.mp3', // Light Click
    tick: 'https://assets.mixkit.co/active_storage/sfx/2599/2599-preview.mp3', // Clock Tick
    unlock: 'https://assets.mixkit.co/active_storage/sfx/1435/1435-preview.mp3', // Success/Unlock
    needleDrop: 'https://assets.mixkit.co/active_storage/sfx/228/228-preview.mp3', // Thump/Static

    // Loops
    crackle: 'https://upload.wikimedia.org/wikipedia/commons/b/bb/Vinyl_crackle.ogg',
    hum: 'https://upload.wikimedia.org/wikipedia/commons/6/61/60Hz_hum.ogg'
};

class AudioController {
    private sounds: Record<string, HTMLAudioElement> = {};
    private initialized = false;

    constructor() {
        if (typeof window !== 'undefined') {
            this.preload();
        }
    }

    private preload() {
        if (this.initialized) return;

        Object.entries(ASSETS).forEach(([key, src]) => {
            const audio = new Audio(src);
            audio.preload = 'auto';

            // Configure loops
            if (key === 'crackle' || key === 'hum') {
                audio.loop = true;
            }

            // Default Volumes
            if (key === 'hum') audio.volume = 0.15;
            if (key === 'crackle') audio.volume = 0.25;

            this.sounds[key] = audio;
        });

        this.initialized = true;
    }

    public play(id: keyof typeof ASSETS, volume: number = 0.6) {
        const sound = this.sounds[id];
        if (sound) {
            sound.currentTime = 0;
            sound.volume = volume;
            sound.play().catch(e => {
                // Ignore autoplay policy errors for UI sounds if interaction hasn't happened yet
                // console.warn('Audio play failed', e);
            });
        }
    }

    public startLoop(id: 'crackle' | 'hum') {
        const sound = this.sounds[id];
        if (sound && sound.paused) {
            sound.volume = id === 'hum' ? 0.15 : 0.25; // Reset to default base
            sound.play().catch(() => {});
        }
    }

    public stopLoop(id: 'crackle' | 'hum') {
        const sound = this.sounds[id];
        if (sound) {
            sound.pause();
            sound.currentTime = 0;
        }
    }

    // Smooth fade in for motor and crackle
    public fadeInLoop(id: 'crackle' | 'hum', targetVolume: number = 0.15, duration: number = 1000) {
        const sound = this.sounds[id];
        if (!sound) return;

        if (sound.paused) {
            sound.volume = 0;
            sound.play().catch(() => {});
        }

        const steps = 20;
        const interval = duration / steps;
        const stepSize = targetVolume / steps;

        let currentStep = 0;
        const fade = setInterval(() => {
            currentStep++;
            // Don't exceed target
            const newVol = Math.min(targetVolume, sound.volume + stepSize);
            sound.volume = newVol;

            if (currentStep >= steps || sound.volume >= targetVolume) {
                clearInterval(fade);
                sound.volume = targetVolume;
            }
        }, interval);
    }

    // Smooth fade out
    public fadeOutLoop(id: 'crackle' | 'hum', duration: number = 500) {
        const sound = this.sounds[id];
        if (!sound || sound.paused) return;

        const steps = 20;
        const startVol = sound.volume;
        const interval = duration / steps;
        const stepSize = startVol / steps;

        let currentStep = 0;
        const fade = setInterval(() => {
            currentStep++;
            const newVol = Math.max(0, sound.volume - stepSize);
            sound.volume = newVol;

            if (currentStep >= steps || sound.volume <= 0) {
                clearInterval(fade);
                sound.pause();
                sound.currentTime = 0;
            }
        }, interval);
    }

    public setVolume(id: keyof typeof ASSETS, volume: number) {
        const sound = this.sounds[id];
        if (sound) {
            sound.volume = Math.max(0, Math.min(1, volume));
        }
    }
}

